function j(
  id: number,
  categoryId: JourneyCategoryId,
  title: string,
  actor: string,
  outcome: string,
  primarySurface: string,
  backendObjects: string[],
  coverage: JourneyCoverage,
  priority: "P0" | "P1" | "P2",
  evidence: string[],
  gaps: string[],
): CustomerJourney {
  return {
    id,
    categoryId,
    title,
    actor,
    outcome,
    primarySurface,
    backendObjects,
    coverage,
    priority,
    evidence,
    gaps,
    acceptance: [
      "User can start the journey from the named surface without developer help.",
      "Required records are created, updated, or displayed through tenant-owned data.",
      "The journey has a visible success state, recoverable failure state, and audit or test evidence.",
    ],
  };
}

