export function journeyCoverageSummary(journeys: CustomerJourney[] = customerJourneys) {
  const byCoverage = journeys.reduce<Record<JourneyCoverage, number>>(
    (counts, journey) => {
      counts[journey.coverage] += 1;
      return counts;
    },
    { verified: 0, interactive: 0, modeled: 0, gap: 0 },
  );

  const p0Open = journeys.filter((journey) => journey.priority === "P0" && journey.coverage !== "verified").length;
  const verifiedPercent = Math.round((byCoverage.verified / journeys.length) * 100);

  return {
    total: journeys.length,
    byCoverage,
    p0Open,
    verifiedPercent,
  };
}
